/**
 * Convert a basic Zod schema to a JSON Schema object.
 */
export function toJsonSchema(schema: any): Record<string, unknown> {
  const typeName = schema._zod?.def?.type;
  switch (typeName) {
    case 'string':
      return { type: 'string' };
    case 'number':
      return { type: 'number' };
    case 'boolean':
      return { type: 'boolean' };
    case 'array':
      return { type: 'array' };
    case 'object':
      return { type: 'object' };
    default:
      return {};
  }
}

import { z } from "../src";
import { expect, test } from "vitest";

test("string min length", () => {
  const schema = z.string().min(3);
  expect(schema.parse("abc")).toBe("abc");
  expect(() => schema.parse("ab")).toThrow();
});

test("string max length", () => {
  const schema = z.string().max(5);
  expect(schema.parse("hello")).toBe("hello");
  expect(() => schema.parse("toolong")).toThrow();
});

test("string email", () => {
  const schema = z.string().email();
  expect(schema.parse("test@example.com")).toBe("test@example.com");
  expect(() => schema.parse("not-an-email")).toThrow();
});

